parameters.jsCode:
// N8N Code node (JavaScript) — normalize Miniflux entries.
//
// Input: items from the upstream Miniflux node. Accepts either
//   - one item whose `.json` is `{entries: [...], total: N}` or an array, or
//   - many items, each being a Miniflux entry object.
//
// Output: a single item with the normalized payload, shape compatible with
// the downstream render step:
//   {window, total_in_window, returned, truncated, max_articles, entries}

const MAX_ARTICLES = 500;
const EXCERPT_CHARS = 500;

function htmlToText(html) {
  if (!html) return "";
  // Drop script/style blocks (content + tags) before stripping the rest.
  let text = html.replace(/<(script|style)\b[^>]*>[\s\S]*?<\/\1>/gi, " ");
  text = text.replace(/<[^>]+>/g, " ");
  // Minimal entity decoding — feeds rarely ship exotic entities.
  text = text
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'");
  return text.replace(/\s+/g, " ").trim();
}

function truncate(text, maxLen) {
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen - 1).trimEnd() + "…";
}

function normalizeEntry(entry, excerptChars) {
  const feed = entry.feed || {};
  const category = feed.category || {};
  return {
    id: entry.id,
    title: (entry.title || "").trim(),
    url: entry.url,
    feed: feed.title || "",
    feed_url: feed.site_url,
    category: category.title || "",
    author: (entry.author || "").trim(),
    published_at: entry.published_at,
    excerpt: truncate(htmlToText(entry.content || ""), excerptChars),
    enriched: false,
  };
}

function collectRawEntries(items) {
  if (items.length === 1) {
    const payload = items[0].json;
    if (payload && Array.isArray(payload.entries)) return [...payload.entries];
    if (Array.isArray(payload)) return [...payload];
    return [payload];
  }
  return items.map((it) => it.json);
}

const rawEntries = collectRawEntries($input.all());
rawEntries.sort((a, b) => {
  const da = a.published_at || "";
  const db = b.published_at || "";
  return da < db ? -1 : da > db ? 1 : 0;
});

const totalInWindow = rawEntries.length;
const isTruncated = totalInWindow > MAX_ARTICLES;
const kept = isTruncated ? rawEntries.slice(-MAX_ARTICLES) : rawEntries;

const entries = kept.map((e) => normalizeEntry(e, EXCERPT_CHARS));
const pubDates = entries.map((e) => e.published_at).filter(Boolean);

const payload = {
  window: {
    from: pubDates.length ? pubDates[0] : null,
    to: pubDates.length ? pubDates[pubDates.length - 1] : null,
  },
  total_in_window: totalInWindow,
  returned: entries.length,
  truncated: isTruncated,
  max_articles: MAX_ARTICLES,
  entries,
};

return [{ json: payload }];

// Chunk entries into batches for the classifier LLM.
// Output: one item per batch — each carries a slim view (id/title/feed/category/short excerpt)
// sized to keep the classifier prompt small and predictable.

const CHUNK_SIZE = 15;
const EXCERPT_CHARS_FOR_CLASSIFIER = 240;

const payload = $input.first().json;
const entries = payload.entries || [];

const chunks = [];
for (let i = 0; i < entries.length; i += CHUNK_SIZE) {
  const slice = entries.slice(i, i + CHUNK_SIZE);
  const slim = slice.map((e) => ({
    id: e.id,
    title: e.title,
    feed: e.feed,
    category: e.category,
    excerpt: (e.excerpt || "").slice(0, EXCERPT_CHARS_FOR_CLASSIFIER),
  }));
  chunks.push({ json: { items: slim, chunk_idx: chunks.length } });
}

return chunks.length ? chunks : [{ json: { items: [], chunk_idx: 0 } }];

// Merge all classifier batches back onto the original entries, group by category.
// Reads the canonical entries from Normalize so we don't rely on the LLM to echo them.
// Reads `category` field from the LLM output, with `slug` fallback and alias map for drift.

function parseLLM(item) {
  const raw =
    item.content ??
    item.text ??
    (item.message && item.message.content) ??
    (typeof item.output === "string" ? item.output : Array.isArray(item.output) ? item.output.map((b) => b.text).join("") : "") ??
    "";
  if (typeof raw !== "string") return raw;
  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) { try { return JSON.parse(fence[1]); } catch (_) {} }
  try { return JSON.parse(raw); } catch (_) {}
  const s = raw.indexOf("{"), e = raw.lastIndexOf("}");
  if (s >= 0 && e > s) { try { return JSON.parse(raw.slice(s, e + 1)); } catch (_) {} }
  return null;
}

const TARGET_SLUGS = ["ia", "infosec", "devops", "diy", "societe"];
const CATEGORY_NAMES = {
  ia: "IA",
  infosec: "Infosec",
  devops: "DevOps",
  diy: "DIY",
  societe: "Société & régulation",
};

// Defensive aliases — model occasionally drifts despite the strict prompt.
const ALIASES = {
  devsecops: "devops",
  dev: "devops",
  webdev: "devops",
  security: "infosec",
  cybersec: "infosec",
  cybersecurity: "infosec",
  vulnerability: "infosec",
  society: "societe",
  société: "societe",
  ai: "ia",
  llm: "ia",
  hardware: "diy",
  hacking: "diy",
  makers: "diy",
};

function normalizeSlug(raw) {
  if (!raw || typeof raw !== "string") return null;
  const t = raw.toLowerCase().trim();
  if (TARGET_SLUGS.includes(t) || t === "appendix") return t;
  if (ALIASES[t]) return ALIASES[t];
  return null; // unknown — caller decides fallback
}

const byId = new Map();
let totalClassified = 0;
let unknownSlugs = new Set();
for (const item of $input.all()) {
  const parsed = parseLLM(item.json);
  const list = (parsed && parsed.classifications) || [];
  for (const c of list) {
    if (c && c.id != null) {
      byId.set(c.id, c);
      totalClassified++;
    }
  }
}

const normalized = $('Normalize').first().json;
const entries = normalized.entries || [];

const buckets = { ia: [], infosec: [], devops: [], diy: [], societe: [], appendix: [] };
for (const e of entries) {
  const cls = byId.get(e.id);
  // Prefer `category` (current schema). Fall back to `slug` only if it looks like a taxonomy value.
  const candidate = cls && (cls.category || cls.slug);
  let slug = normalizeSlug(candidate);
  if (!slug) {
    if (candidate) unknownSlugs.add(String(candidate).toLowerCase());
    slug = "appendix"; // unclassified → appendix
  }
  buckets[slug].push({
    ...e,
    importance: cls ? Number(cls.importance) || 1 : 1,
    cluster_hint: cls ? (cls.cluster_hint || "") : "",
  });
}

for (const k of Object.keys(buckets)) {
  buckets[k].sort((a, b) => {
    if (b.importance !== a.importance) return b.importance - a.importance;
    return (b.published_at || "") < (a.published_at || "") ? -1 : 1;
  });
}

return [{
  json: {
    buckets,
    meta: {
      window: normalized.window,
      total_in_window: normalized.total_in_window,
      returned: normalized.returned,
      truncated: normalized.truncated,
      max_articles: normalized.max_articles,
    },
    category_names: CATEGORY_NAMES,
    debug: {
      total_entries: entries.length,
      total_classified: totalClassified,
      unclassified: entries.length - byId.size,
      unknown_slugs_seen: Array.from(unknownSlugs),
      bucket_sizes: Object.fromEntries(Object.entries(buckets).map(([k, v]) => [k, v.length])),
    },
  },
}];

// Emit one item per non-empty main category. Cap to MAX_PER_CATEGORY by
// importance so a noisy day can't blow the synth context. Appendix bucket
// is handled downstream in Assemble Spec — no LLM call needed for it.

const TARGET_SLUGS = ["ia", "infosec", "devops", "diy", "societe"];
const MAX_PER_CATEGORY = 40;
const { buckets, category_names } = $input.first().json;

const items = [];
for (const slug of TARGET_SLUGS) {
  // Entries are already sorted by importance desc in Aggregate Classifications.
  const list = (buckets[slug] || []).slice(0, MAX_PER_CATEGORY);
  if (list.length === 0) continue;
  const slim = list.map((e) => ({
    id: e.id,
    title: e.title,
    url: e.url,
    feed: e.feed,
    published_at: e.published_at,
    excerpt: e.excerpt,
    importance: e.importance,
    cluster_hint: e.cluster_hint,
  }));
  items.push({
    json: { slug, name: category_names[slug], entries: slim },
  });
}

if (items.length === 0) {
  // Sentinel so Assemble Spec still runs (all-appendix edge case).
  return [{ json: { slug: null, name: "", entries: [], skip_synth: true } }];
}
return items;

