// Flatten topics across all categories into one item per topic, hydrating each
// source with full entry data (excerpt etc.) so the deep-dive LLM has the prose.

function parseLLM(item) {
  const raw =
    item.content ??
    item.text ??
    (item.message && item.message.content) ??
    (typeof item.output === "string" ? item.output : Array.isArray(item.output) ? item.output.map((b) => b.text).join("") : "") ??
    "";
  if (typeof raw !== "string") return raw;
  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) { try { return JSON.parse(fence[1]); } catch (_) {} }
  try { return JSON.parse(raw); } catch (_) {}
  const s = raw.indexOf("{"), e = raw.lastIndexOf("}");
  if (s >= 0 && e > s) { try { return JSON.parse(raw.slice(s, e + 1)); } catch (_) {} }
  return null;
}

const aggregate = $('Aggregate Classifications').first().json;
const buckets = aggregate.buckets || {};

// Build a global id -> entry lookup across all buckets.
const byId = new Map();
for (const k of Object.keys(buckets)) {
  for (const e of buckets[k]) byId.set(e.id, e);
}

const items = [];
for (const llmItem of $input.all()) {
  const parsed = parseLLM(llmItem.json);
  if (!parsed || !parsed.slug || !Array.isArray(parsed.topics)) continue;
  parsed.topics.forEach((topic, idx) => {
    const ids = Array.isArray(topic.source_ids) ? topic.source_ids : [];
    const sources = ids
      .map((id) => byId.get(id))
      .filter(Boolean)
      .map((e) => ({
        id: e.id,
        title: e.title,
        url: e.url,
        feed: e.feed,
        published_at: e.published_at,
        excerpt: e.excerpt,
        importance: e.importance,
        cluster_hint: e.cluster_hint,
      }));
    if (sources.length === 0) return;
    items.push({
      json: {
        topic_key: `${parsed.slug}:${idx}`,
        category_slug: parsed.slug,
        category_name: parsed.name,
        topic_title: topic.title,
        lede_seed: topic.lede_seed || "",
        sources,
      },
    });
  });
}

if (items.length === 0) {
  return [{ json: { topic_key: "__none__", category_slug: null, category_name: "", topic_title: "", lede_seed: "", sources: [], skip_deep: true } }];
}
return items;

