// Merge per-category synth structure + per-topic deep-dive ledes + meta + appendix
// into the final digest spec. Render HTML expects this shape.

function parseLLM(item) {
  const raw =
    item.content ??
    item.text ??
    (item.message && item.message.content) ??
    (typeof item.output === "string" ? item.output : Array.isArray(item.output) ? item.output.map((b) => b.text).join("") : "") ??
    "";
  if (typeof raw !== "string") return raw;
  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) { try { return JSON.parse(fence[1]); } catch (_) {} }
  try { return JSON.parse(raw); } catch (_) {}
  const s = raw.indexOf("{"), e = raw.lastIndexOf("}");
  if (s >= 0 && e > s) { try { return JSON.parse(raw.slice(s, e + 1)); } catch (_) {} }
  return null;
}

const MONTHS_FR = ["janvier","février","mars","avril","mai","juin","juillet","août","septembre","octobre","novembre","décembre"];

function fmtDateFR(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (isNaN(d)) return "";
  const dd = String(d.getUTCDate()).padStart(2, "0");
  const mo = String(d.getUTCMonth() + 1).padStart(2, "0");
  const hh = String(d.getUTCHours()).padStart(2, "0");
  const mi = String(d.getUTCMinutes()).padStart(2, "0");
  return `${dd}/${mo} ${hh}:${mi}`;
}

function fmtHumanFR(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (isNaN(d)) return "";
  const day = d.getUTCDate();
  const month = MONTHS_FR[d.getUTCMonth()];
  const year = d.getUTCFullYear();
  const hh = String(d.getUTCHours()).padStart(2, "0");
  const mi = String(d.getUTCMinutes()).padStart(2, "0");
  return `${day} ${month} ${year} ${hh}:${mi} UTC`;
}

function frenchLong(iso) {
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return `${d.getUTCDate()} ${MONTHS_FR[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

const TARGET_SLUGS = ["ia", "infosec", "devops", "diy", "societe"];
const CATEGORY_NAMES = {
  ia: "IA",
  infosec: "Infosec",
  devops: "DevOps",
  diy: "DIY",
  societe: "Société & régulation",
};

const aggregate = $('Aggregate Classifications').first().json;
const buckets = aggregate.buckets || {};
const meta = aggregate.meta || {};

// 1. Synth Category outputs — category structure (titles + source_ids + lede_seed).
const synthBySlug = {};
for (const item of $('Synthesize Category').all()) {
  const parsed = parseLLM(item.json);
  if (!parsed || !parsed.slug || !Array.isArray(parsed.topics)) continue;
  synthBySlug[parsed.slug] = parsed;
}

// 2. Deep Dive outputs — rich ledes by topic_key.
const deepByKey = {};
for (const item of $input.all()) {
  const parsed = parseLLM(item.json);
  if (!parsed || !parsed.topic_key) continue;
  deepByKey[parsed.topic_key] = parsed;
}

// 3. id -> entry lookup, used as fallback when deep dive didn't return sources[].
const entryById = new Map();
for (const k of Object.keys(buckets)) {
  for (const e of buckets[k]) entryById.set(e.id, e);
}

function buildSources(deepSources, fallbackIds) {
  if (Array.isArray(deepSources) && deepSources.length) {
    return deepSources.map((s) => ({
      feed: s.feed || "",
      date: s.date || "",
      url: s.url || "",
      title: s.title || "",
    }));
  }
  return (fallbackIds || [])
    .map((id) => entryById.get(id))
    .filter(Boolean)
    .map((e) => ({
      feed: e.feed || "",
      date: fmtDateFR(e.published_at),
      url: e.url || "",
      title: e.title || "",
    }));
}

const categories = [];
for (const slug of TARGET_SLUGS) {
  const synth = synthBySlug[slug];
  if (!synth || !Array.isArray(synth.topics) || synth.topics.length === 0) continue;
  const topics = [];
  synth.topics.forEach((topic, idx) => {
    const key = `${slug}:${idx}`;
    const deep = deepByKey[key];
    const lede = (deep && deep.lede_html) ? deep.lede_html : (topic.lede_seed || "");
    const sources = buildSources(deep && deep.sources, topic.source_ids);
    if (sources.length === 0) return;
    topics.push({
      title: topic.title || "",
      lede_html: lede,
      sources,
    });
  });
  if (topics.length === 0) continue;
  categories.push({
    slug,
    name: synth.name || CATEGORY_NAMES[slug],
    tagline: synth.tagline,
    topics,
  });
}

const appendixBucket = buckets.appendix || [];
const appendix = appendixBucket.slice(0, 10).map((e) => ({
  url: e.url,
  title: e.title,
  note: "",
}));

const wFrom = meta.window && meta.window.from ? fmtHumanFR(meta.window.from) : "";
const wTo = meta.window && meta.window.to ? fmtHumanFR(meta.window.to) : "";
const totalArticles = meta.returned || 0;
const count = `${totalArticles} article${totalArticles > 1 ? "s" : ""}`;

const day = (meta.window && meta.window.to)
  ? new Date(meta.window.to).toISOString().slice(0, 10)
  : new Date().toISOString().slice(0, 10);

let headline = "Digest tech-watch du jour";
const allTopics = categories.flatMap((c) => c.topics.map((t) => ({ ...t, _cat: c.name })));
const strongestTopic = allTopics.sort((a, b) => (b.sources || []).length - (a.sources || []).length)[0];
if (strongestTopic && strongestTopic.title) {
  headline = strongestTopic.title.length > 70
    ? strongestTopic.title.slice(0, 67) + "…"
    : strongestTopic.title;
}

const titleTag = `Digest tech-watch — ${frenchLong(day)}`;

const alert = meta.truncated
  ? `<strong>Truncation</strong> — ${meta.total_in_window} articles dans la fenêtre, capés aux ${meta.max_articles} plus récents.`
  : "";

const footer = `Athanor - ${totalArticles} articles agrégés`;

const spec = {
  date: day,
  title_tag: titleTag,
  headline,
  window: { from: wFrom, to: wTo, count },
  alert,
  categories,
  appendix,
  footer,
};

for (const k of ["date", "headline", "categories"]) {
  if (spec[k] == null) throw new Error(`Spec missing required field: ${k}`);
}

return [{ json: spec }];

// Strip HTML + cap length before returning to the calling LLM, so a
// fetched page can't blow the model's context window.

const MAX_CHARS = 3000;

function htmlToText(html) {
  if (!html) return "";
  let text = html.replace(/<(script|style|noscript)\b[^>]*>[\s\S]*?<\/\1>/gi, " ");
  text = text.replace(/<[^>]+>/g, " ");
  text = text
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'");
  return text.replace(/\s+/g, " ").trim();
}

const j = $input.first().json;
let raw = "";
if (typeof j === "string") raw = j;
else if (j) raw = j.data ?? j.body ?? j.content ?? (typeof j === "object" ? JSON.stringify(j) : "");

const text = htmlToText(String(raw || ""));
const out = text.length > MAX_CHARS ? text.slice(0, MAX_CHARS) + "…" : text;

return [{ json: { content: out, length: out.length } }];

// Decode the GitHub contents response (base64 JSON) into a memory object.
// Tolerates the first-run 404 (Load Memory has onError=continueRegularOutput).
const WINDOW_DAYS = 30;
const j = $input.first() ? $input.first().json : {};

let memory = { themes: [], watchlist: [], tensions: [], strategy_notes: [], updated_at: null };
let sha = null;
try {
  if (j && j.content && !j.error) {
    sha = j.sha || null;
    const decoded = Buffer.from(j.content, "base64").toString("utf8");
    const parsed = JSON.parse(decoded);
    if (parsed && typeof parsed === "object") {
      memory = { themes: [], watchlist: [], tensions: [], strategy_notes: [], updated_at: null, ...parsed };
    }
  }
} catch (_) {}

if (!Array.isArray(memory.themes)) memory.themes = [];
if (!Array.isArray(memory.watchlist)) memory.watchlist = [];
if (!Array.isArray(memory.tensions)) memory.tensions = [];
if (!Array.isArray(memory.strategy_notes)) memory.strategy_notes = [];

// Prune themes / watchlist not seen within the window.
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - WINDOW_DAYS);
memory.themes = memory.themes.filter((t) => {
  const d = new Date(t.last_seen || 0);
  return !isNaN(d) && d >= cutoff;
});
memory.watchlist = memory.watchlist.filter((w) => {
  const d = new Date(w.since || 0);
  return !isNaN(d) && d >= cutoff;
});

// Build a compact summary string to inject into the editorial prompts.
const lines = memory.themes.slice(0, 25).map((t) => {
  const cat = t.category ? `[${t.category}] ` : "";
  const seen = (t.first_seen || "?") + "→" + (t.last_seen || "?");
  const note = t.note ? " — " + t.note : "";
  return `- ${cat}${t.label || "?"} : ${t.momentum || "?"} (${seen})${note}`;
});
const tens = memory.tensions.slice(0, 8).map((t) => "- " + (t.label || "") + (t.note ? " : " + t.note : ""));
const watch = memory.watchlist.slice(0, 12).map((w) => {
  const cat = w.category ? `[${w.category}] ` : "";
  return `- ${cat}${w.label || "?"}${w.note ? " : " + w.note : ""} (depuis ${w.since || "?"})`;
});
let summary = "";
if (memory.strategy_notes.length) {
  summary += "Notes stratégiques:\n" + memory.strategy_notes.map((s) => "- " + s).join("\n") + "\n\n";
}
if (tens.length) summary += "Tensions de fond:\n" + tens.join("\n") + "\n\n";
if (watch.length) summary += "À surveiller (signaux faibles):\n" + watch.join("\n") + "\n\n";
summary += lines.length
  ? "Thèmes en cours (≤30j):\n" + lines.join("\n")
  : "Aucune mémoire antérieure (premier run ou fenêtre vide).";
if (summary.length > 4000) summary = summary.slice(0, 4000) + "…";

return [{ json: { memory, sha, summary, window_days: WINDOW_DAYS } }];

