// Validate the LLM output. Write the MEMORY subset to trends.json (working doc).
// Carry forward everything the page-doc + atomic commit need.
function parseLLM(item) {
  const raw =
    item.text ??
    item.content ??
    (typeof item.output === "string" ? item.output : "") ??
    (item.message && item.message.content) ??
    "";
  if (typeof raw !== "string") return raw;
  const fence = raw.match(/\`\`\`(?:json)?\s*([\s\S]*?)\`\`\`/i);
  if (fence) { try { return JSON.parse(fence[1]); } catch (_) {} }
  try { return JSON.parse(raw); } catch (_) {}
  const s = raw.indexOf("{"), e = raw.lastIndexOf("}");
  if (s >= 0 && e > s) { try { return JSON.parse(raw.slice(s, e + 1)); } catch (_) {} }
  return null;
}

const WINDOW_DAYS = 30;
const prev = $('Parse Memory').first().json;
const digest = $('Assemble Spec').first().json;
const today = digest.date || new Date().toISOString().slice(0, 10);
const pm = (prev && prev.memory) || {};

const llm = parseLLM($input.first().json) || {};

// --- MEMORY subset (internal working doc) ---
const mem = {
  themes: Array.isArray(llm.themes) ? llm.themes : (pm.themes || []),
  watchlist: Array.isArray(llm.watchlist) ? llm.watchlist : (pm.watchlist || []),
  tensions: Array.isArray(llm.tensions) ? llm.tensions : (pm.tensions || []),
  strategy_notes: Array.isArray(llm.strategy_notes) ? llm.strategy_notes : (pm.strategy_notes || []),
};
const cutoff = new Date(today);
cutoff.setDate(cutoff.getDate() - WINDOW_DAYS);
mem.themes = mem.themes
  .filter((t) => t && t.label)
  .filter((t) => { const d = new Date(t.last_seen || today); return !isNaN(d) && d >= cutoff; })
  .slice(0, 40);
mem.watchlist = mem.watchlist
  .filter((w) => w && w.label)
  .filter((w) => { const d = new Date(w.since || today); return !isNaN(d) && d >= cutoff; })
  .slice(0, 12);
mem.tensions = mem.tensions.filter((t) => t && t.label).slice(0, 8);
mem.strategy_notes = mem.strategy_notes.filter(Boolean).slice(0, 6);
mem.updated_at = today;

const trends_b64 = Buffer.from(JSON.stringify(mem, null, 2), "utf8").toString("base64");
const digest_b64 = Buffer.from(JSON.stringify(digest), "utf8").toString("base64");

return [{ json: {
  today,
  sha: prev.sha || null,
  message: `N8N - Digest + tendances ${today}`,
  digest_path: `src/content/digests/${today}.json`,
  digest_b64,
  trends_path: "data/trends.json",
  trends_b64,
  mem,   // validated memory, for the page doc
  llm,   // raw LLM output (synthesis + currents), for the page doc
} }];

// Assemble the dedicated, self-contained page document (tendances.json).
// synthesis + currents from the LLM, with graceful fallback; lists copied from memory.
const bm = $('Build Memory File').first().json;
const mem = bm.mem || {};
const llm = bm.llm || {};
const today = bm.today;

let synthesis = (llm.synthesis && typeof llm.synthesis === "object") ? llm.synthesis : {};
synthesis = {
  headline: synthesis.headline || ((mem.tensions && mem.tensions[0] && mem.tensions[0].label) || "État de la veille"),
  narrative: synthesis.narrative || ((mem.strategy_notes && mem.strategy_notes[0]) || ""),
};

const currents = (Array.isArray(llm.currents) ? llm.currents : [])
  .filter((c) => c && c.label)
  .map((c) => ({
    label: c.label,
    note: c.note || "",
    categories: Array.isArray(c.categories) ? c.categories.filter(Boolean).slice(0, 5) : [],
  }))
  .slice(0, 6);

const page = {
  updated_at: today,
  synthesis,
  currents,
  themes: mem.themes || [],
  watchlist: mem.watchlist || [],
  tensions: mem.tensions || [],
};

const tendances_b64 = Buffer.from(JSON.stringify(page, null, 2), "utf8").toString("base64");
return [{ json: { tendances_path: "src/content/tendances.json", tendances_b64 } }];

const CHUNK_SIZE = 50;
const ids = $('Normalize').first().json.entries.map(e => e.id);
const chunks = [];
for (let i = 0; i < ids.length; i += CHUNK_SIZE) {
  chunks.push({ json: { entry_ids: ids.slice(i, i + CHUNK_SIZE), status: "read" } });
}
return chunks;
